'use strict';(function(){const b={cache:!0};b.doc={id:'id',field:['title','content'],store:['title','href','section']};const a=FlexSearch.create('balance',b);window.bookSearchIndex=a,a.add({id:0,href:'/wiki/github/actions/',title:"Actions",section:"Wikis",content:"Github Actions #  Github Actions 是一套基于 github 的自动化执行框架，可以自定义各种 workflow 及工具来满足 CI, CD 相关的各种需求。\n创建一个容器的 action #  Github Demo: airdb actions\nRefer: https://help.github.com/en/actions/creating-actions/creating-a-docker-container-action\n主体思路：\n通过执行 docker run 命令实现 actions 操作。\nWorkflow:\n action.yml 中配置, 启用自定义的 action , 增加 input 变量作为 docker run 参数 调用自定义的 action , 从 env 中获取 GITHUB_EVENT_PATH, 读取 event.json 全部内容 代码中进行自定义操作 设置输出, 如 echo \u0026ldquo;::set-output name=time::$time\u0026rdquo;  "}),a.add({id:1,href:'/wiki/github/fork/',title:"Fork",section:"Wikis",content:"Github 技巧 #  Gitlab 或 Github Fork 后如何同步源的新更新内容？ #  给 fork 配置远程库 #    查看远程状态 git remote -v\n  确定一个将被同步给 fork 远程的上游仓库 git remote add upstream https://github.com/bfenetworks/bfe\n  再次查看状态确认是否配置成功。 git remote -v\n  同步 fork #   从上游仓库 fetch 分支和提交点，提交给本地 master，并会被存储在一个本地分支 upstream/master  git fetch upstream  切换到本地主分支(如果不在的话)  git checkout develop\n 把 upstream/master 分支合并到本地 master 上，这样就完成了同步，并且不会丢掉本地修改的内容。  git merge upstream/develop\n 如果想更新到 GitHub 的 fork 上，直接  git push origin develop\n"}),a.add({id:2,href:'/wiki/github/makefile/',title:"Makefile",section:"Wikis",content:"Makefile #  Command line arguments #  myos = $(word 1, $@) ifndef $myos myos = \u0026#34;$(shell uname | tr A-Z a-z)\u0026#34; endif Examples #  Go Makefile #  -include .env VERSION := $(shell git describe --tags) BUILD := $(shell git rev-parse --short HEAD) PROJECTNAME := $(shell basename \u0026#34;$(PWD)\u0026#34;) # Go related variables. GOBASE := $(shell pwd) GOPATH := $(GOBASE)/vendor:$(GOBASE) GOBIN := $(GOBASE)/bin GOFILES := $(wildcard *.go) # Use linker flags to provide version/build settings LDFLAGS=-ldflags \u0026#34;-X=main.Version=$(VERSION)-X=main.Build=$(BUILD)\u0026#34; # Redirect error output to a file, so we can show it in development mode. STDERR := /tmp/.$(PROJECTNAME)-stderr.txt # PID file will keep the process id of the server PID := /tmp/.$(PROJECTNAME).pid # Make is verbose in Linux. Make it silent. MAKEFLAGS += --silent ## install: Install missing dependencies. Runs `go get` internally. e.g; make install get=github.com/foo/bar install: go-get ## start: Start in development mode. Auto-starts when code changes. start: @bash -c \u0026#34;trap \u0026#39;make stop\u0026#39; EXIT; $(MAKE)clean compile start-server watch run=\u0026#39;make clean compile start-server\u0026#39;\u0026#34; ## stop: Stop development mode. stop: stop-server start-server: stop-server @echo \u0026#34; \u0026gt; $(PROJECTNAME)is available at $(ADDR)\u0026#34; @-$(GOBIN)/$(PROJECTNAME) 2\u0026gt;\u0026amp;1 \u0026amp; echo $$! \u0026gt; $(PID) @cat $(PID) | sed \u0026#34;/^/s/^/ \\\u0026gt; PID: /\u0026#34; stop-server: @-touch $(PID) @-kill `cat $(PID)` 2\u0026gt; /dev/null || true @-rm $(PID) ## watch: Run given command when code changes. e.g; make watch run=\u0026#34;echo \u0026#39;hey\u0026#39;\u0026#34; watch: @GOPATH=$(GOPATH) GOBIN=$(GOBIN) yolo -i . -e vendor -e bin -c \u0026#34;$(run)\u0026#34; restart-server: stop-server start-server ## compile: Compile the binary. compile: @-touch $(STDERR) @-rm $(STDERR) @-$(MAKE) -s go-compile 2\u0026gt; $(STDERR) @cat $(STDERR) | sed -e \u0026#39;1s/.*/\\nError:\\n/\u0026#39; | sed \u0026#39;s/make\\[.*/ /\u0026#39; | sed \u0026#34;/^/s/^/ /\u0026#34; 1\u0026gt;\u0026amp;2 ## exec: Run given command, wrapped with custom GOPATH. e.g; make exec run=\u0026#34;go test ./...\u0026#34; exec: @GOPATH=$(GOPATH) GOBIN=$(GOBIN) $(run) ## clean: Clean build files. Runs `go clean` internally. clean: @-rm $(GOBIN)/$(PROJECTNAME) 2\u0026gt; /dev/null @-$(MAKE) go-clean go-compile: go-get go-build go-build: @echo \u0026#34; \u0026gt; Building binary...\u0026#34; @GOPATH=$(GOPATH) GOBIN=$(GOBIN) go build $(LDFLAGS) -o $(GOBIN)/$(PROJECTNAME) $(GOFILES) go-generate: @echo \u0026#34; \u0026gt; Generating dependency files...\u0026#34; @GOPATH=$(GOPATH) GOBIN=$(GOBIN) go generate $(generate) go-get: @echo \u0026#34; \u0026gt; Checking if there is any missing dependencies...\u0026#34; @GOPATH=$(GOPATH) GOBIN=$(GOBIN) go get $(get) go-install: @GOPATH=$(GOPATH) GOBIN=$(GOBIN) go install $(GOFILES) go-clean: @echo \u0026#34; \u0026gt; Cleaning build cache\u0026#34; @GOPATH=$(GOPATH) GOBIN=$(GOBIN) go clean .PHONY: help all: help help: Makefile @echo @echo \u0026#34; Choose a command run in \u0026#34;$(PROJECTNAME)\u0026#34;:\u0026#34; @echo @sed -n \u0026#39;s/^##//p\u0026#39; $\u0026lt; | column -t -s \u0026#39;:\u0026#39; | sed -e \u0026#39;s/^/ /\u0026#39; @echo "}),a.add({id:3,href:'/wiki/github/README/',title:"Readme",section:"Wikis",content:"Github 使用 #  记录一些 Github 信息\n"}),a.add({id:4,href:'/wiki/linux/bash-prog/',title:"Bash Prog",section:"Wikis",content:"Bash Programming #  学习地址 #   BASH Programming - Introduction HOW-TO\n编程规范 #   Google Shell Code Style\n一些 Debug 技巧 #  set -x set -e export PS4='+${BASH_SOURCE}:${LINENO}:${FUNCNAME[0]}: ' echo \u0026quot;Today is $(date %Y-%m-%d)\u0026quot; set +x 说明： PS4 The value of this parameter is expanded as with PS1 and the value is printed before each command bash displays during an execution trace. The first character of PS4 is replicated multiple times, as neces-sary, to indicate multiple levels of indirection. The default is ”+ ”.\n::: tip 日志输出\n_log() { if [ \u0026quot;$_DEBUG\u0026quot; == \u0026quot;true\u0026quot; ]; then echo 1\u0026gt;\u0026amp;2 \u0026quot;$@\u0026quot; fi } :::\n"}),a.add({id:5,href:'/wiki/linux/bash/',title:"Bash",section:"Wikis",content:"Bash #  Profile 执行顺序 #  登录 Linux 时，首先启动 /etc/profile 文件，然后再启动用户目录下的 ~/.bash_profile、 ~/.bash_login或 ~/.profile文件中的其中一个, 一般还会执行 ~/.bashrc文件。\n~/.bash_logout，每次退出系统或退出bash shell时,执行该文件。\n❗️注意: 部分系统只读取~/.bashrc (不读取 ~/.bash_prfoile), 如 BusyBox\nBash 环境变量 #  # 公共 $LOGNAME: 登录用户名 $HOME: 当前用户家目录 export PS1=\u0026quot;[\\u@\\H \\W]\\\\$ \u0026quot; export HISTTIMEFORMAT=\u0026quot;%F %T `whoami` \u0026quot; export TMOUT=600 # 600 秒内用户无操作就字段断开终端 常用别名 #  alias ipsort=\u0026quot;sort -t\u0026quot;.\u0026quot; -k1,1n -k2,2n -k3,3n -k4,4n\u0026quot; alias ipsortr=\u0026quot;sort -t\u0026quot;.\u0026quot; -k1,1nr -k2,2nr -k3,3nr -k4,4nr\u0026quot; 常用命令 #  date +\u0026quot;%s\u0026quot; # uninx timestamp date -d @1548987653 # linux, unix timestamp 转 \u0026quot;Fri Feb 1 10:20:53 CST 2019\u0026quot; sudo date -d 1548987653 # mac, unix timestamp 转 \u0026quot;Fri Feb 1 10:20:53 CST 2019\u0026quot; jq # Command-line JSON processor, Download from https://github.com/stedolan/jq "}),a.add({id:6,href:'/wiki/linux/dhcp/',title:"DHCP",section:"Wikis",content:"DHCP #  Dynamic Host Configuration Protocol\nBest Practice\ndhcp/conf/dhcpd.conf #  include \u0026quot;/var/www/html/autoinstall/dhcp/host\u0026quot;; ddns-update-style interim; ignore client-updates; allow unknown-clients; ping-check true; option perform-mask-discovery true; option router-discovery true; #option ntp-servers 10.4.18.10,10.4.18.11; # hz ntp #option time-offset -18000; # Eastern Standard Time. #option domain-name-servers 10.0.1.127,203.196.0.6; option domain-search \u0026quot;airdb.io\u0026quot;; default-lease-time 3600; max-lease-time 4800; group host_pool { default-lease-time 600; max-lease-time 600; allow bootp; allow booting; filename \u0026quot;/pxelinux.0\u0026quot;; option dhcp-renewal-time 10; subnet 10.0.0.0 netmask 255.255.255.0 { option subnet-mask 255.255.255.0; option routers 10.0.0.1; #default routes range dynamic-bootp 10.0.0.2 10.0.0.200; } }  dhcp/conf/hosts #  host rmc1.airdb.io {hardware ethernet 00:01:02:03:04:80 ;fixed-address 10.0.0.253 ;} host dean.airdb.io { hardware ethernet f0:76:1c:02:b1:10 ;fixed-address 10.0.0.251;} host dhcp_01 { hardware ethernet 00:8c:fa:eb:b4:bc ;fixed-address 10.0.0.01 ;} host h_02 { hardware ethernet 00:8c:fa:eb:b2:d4 ;fixed-address 10.0.0.02 ;} host h_03 { hardware ethernet 00:8c:fa:eb:b4:0c ;fixed-address 10.0.0.03 ;} host h_04 { hardware ethernet 00:8c:fa:eb:b8:08 ;fixed-address 10.0.0.04 ;} host h_05 { hardware ethernet 00:8c:fa:eb:b4:d0 ;fixed-address 10.0.0.05 ;} host h_06 { hardware ethernet 00:8c:fa:eb:b4:78 ;fixed-address 10.0.0.06 ;}  /etc/xinetd.d/tftp #  service tftp { socket_type	= dgram protocol	= udp wait	= yes user	= root server	= /usr/sbin/in.tftpd server_args	= -B 1380 -v -s /var/www/html/autoinstall/tftpboot disable	= no per_source	= 11 cps	= 100 2 flags	= IPv4 }  "}),a.add({id:7,href:'/wiki/linux/monitor/',title:"Monitor",section:"Wikis",content:"Monitor #  Host Monitor #   Linux系统内存使用率该怎么计算\npsutil module #   Go: https://github.com/shirou/gopsutil\n Python: https://github.com/giampaolo/psutil\n"}),a.add({id:8,href:'/wiki/linux/nginx/',title:"Nginx",section:"Wikis",content:"Nginx #  公共配置 #  说明： conf/nginx.conf 中存放在公共配置中， conf.d/upstream.conf 中存放upstream配置， conf.d/host.conf 中存放 location 等其他配置。\n# For more information on configuration, see: # * Official English Documentation: http://nginx.org/en/docs/ # * Official Russian Documentation: http://nginx.org/ru/docs/ worker_processes auto; error_log logs/error.log; pid run/nginx.pid; # Load dynamic modules. See /usr/share/nginx/README.dynamic. # include /usr/share/nginx/modules/*.conf; events { worker_connections 2048; } http { include /etc/nginx/mime.types; default_type application/octet-stream; #log_format main '$remote_addr - $host [$time_local] \u0026quot;$request\u0026quot; ' '$status $body_bytes_sent \u0026quot;$http_referer\u0026quot; ' '\u0026quot;$http_user_agent\u0026quot; \u0026quot;$http_x_forwarded_for\u0026quot;'; log_format main '$time_iso8601|$status|$remote_addr|$host|$server_port|$server_protocol|$request_method|$host$request_uri|$request_filename|$content_type|$bytes_sent|$body_bytes_sent|$request_time|$http_user_agent|$http_Tencent_LeakScan|$upstream_addr|$http_referer'; error_log logs/error.log; keepalive_timeout 30; server_names_hash_max_size 512; server_names_hash_bucket_size 128; server_tokens off; sendfile on; tcp_nopush off; tcp_nodelay on; #keepalive_timeout 3 10; client_max_body_size 8m; client_header_timeout 30; client_body_timeout 30; send_timeout 30; #fastcgi_connect_timeout 300; #fastcgi_send_timeout 300; #fastcgi_read_timeout 300; fastcgi_buffer_size 64k; fastcgi_buffers 8 64k; fastcgi_busy_buffers_size 128k; fastcgi_intercept_errors on; gzip on; gzip_min_length 1024; gzip_buffers 4 8k; gzip_http_version 1.0; gzip_comp_level 1; gzip_vary on; gzip_types text/plain text/css application/x-javascripts text/xml application/xml application/xml+rss text/javascript; proxy_next_upstream error timeout invalid_header http_500 http_503; proxy_set_header Host $host; proxy_set_header X-Real-IP $remote_addr; proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for; proxy_intercept_errors on; proxy_redirect off; port_in_redirect off; # Load modular configuration files from the /etc/nginx/conf.d directory. # See http://nginx.org/en/docs/ngx_core_module.html#include # dor more information. include conf.d/*.conf; ipip_db /data/app/nginx/modules/17monipdb.datx 60m; ipip_parse_ip $remote_addr; # ipip_parse_ip $http_x_forwarded_for; proxy_set_header ip $http_x_forwarded_for; proxy_set_header country_code $ipip_country_code; proxy_set_header country $ipip_country_name; proxy_set_header province $ipip_region_name; proxy_set_header city $ipip_city_name; proxy_set_header owner $ipip_owner_domain; proxy_set_header isp $ipip_isp_domain; proxy_set_header idc $ipip_idc; proxy_set_header latitude $ipip_latitude; proxy_set_header longitude $ipip_longitude; } "}),a.add({id:9,href:'/wiki/linux/README/',title:"Readme",section:"Wikis",content:"Linux Practice #  适用人群 #  建议人群：有一定 Linux 使用经验。\n序语 #  本该是我在日常工作中使用到的一些 linux 小技巧或实践，不一定对每一个人有用，但应该会有一些参考意义。\n如果你也有简单易用的技巧，欢迎 PR，一起成长吧！\n"}),a.add({id:10,href:'/wiki/linux/ssh/',title:"SSH",section:"Wikis",content:"SSH #  ssh(Secure Shell) 是典型的 C/S 框架，包含服务端(sshd) 和 客户端(ssh)\n客户端 ssh #  管理大规模机群的时候会觉得经常输入yes比较麻烦，尤其是主机重装后，还需要清理 known_hosts 文件，可以进行配置一下，这样用起来更顺手。 配置 $HOME/.ssh/config如下:\nStrictHostKeyChecking no UserKnownHostsFile /dev/null ConnectTimeout 3 或\nalias ssh=\u0026quot;ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -o \\ ConnectTimeout=3\u0026quot; 服务端 sshd #  配置文件 /etc/ssh/sshd_config\nBanner /etc/ssh/banner_file # 登录主机时显示的一个 banner，可以是欢迎语 PasswordAuthentication no PermitRootLogin yes # 允许root用户远程登录 生成证书 #  ssh-keygen -b 2048 -C $HOSTNAME\n排障 #  如果目标机器无法 ssh，可以使用 -v 参数排查详情。\n::: warning 个别主机，可能会设置 /etc/hosts.allow 或 /etc/hosts.deny。 :::\n"}),a.add({id:11,href:'/wiki/linux/tools/',title:"Tools",section:"Wikis",content:"Command Tools #  介绍一些常用的命令行工具\n常用工具 #  tmux: 一个优秀的终端复用软件，类似GNU Screen jq: Command-line JSON processor, https://github.com/stedolan/jq "}),a.add({id:12,href:'/wiki/linux/vim/',title:"Vim",section:"Wikis",content:"VIM #  vundle 搭建很方便\n  git clone https://github.com/gmarik/Vundle.vim.git ~/.vim/bundle/Vundle.vim\n  修改 .vimrc\n  打开vim在底行模式下输入 BundleInstall\n  如果还需要其他插件，可以使用 BundleSearch 进行在线查找插件\n  配置文件内容 #  filetype off syntax on set rtp+=~/.vim/bundle/Vundle.vim call vundle#begin() \u0026quot; 加载插件 Plugin 'VundleVim/Vundle.vim' Plugin 'scrooloose/nerdtree' Plugin 'vim-airline/vim-airline' Plugin 'fatih/vim-go' Plugin 'vim-airline/vim-airline-themes' Plugin 'michaelHL/awesome-vim-colorschemes' Plugin 'Tagbar' Plugin 'Tabular' call vundle#end() filetype plugin indent on \u0026quot; required \u0026quot; 打开自动定位到最后编辑的位置, 需要确认.viminfo当前用户可写 if has(\u0026quot;autocmd\u0026quot;) au BufReadPost * if line(\u0026quot;'\\\u0026quot;\u0026quot;) \u0026gt; 1 \u0026amp;\u0026amp; line(\u0026quot;'\\\u0026quot;\u0026quot;) \u0026lt;= line(\u0026quot;$\u0026quot;) | exe \u0026quot;normal! g'\\\u0026quot;\u0026quot; | endif endif \u0026quot; 快捷键 map \u0026lt;C-h\u0026gt; \u0026lt;C-w\u0026gt;\u0026lt;C-h\u0026gt; map \u0026lt;C-j\u0026gt; \u0026lt;C-w\u0026gt;\u0026lt;C-j\u0026gt; map \u0026lt;C-l\u0026gt; \u0026lt;C-w\u0026gt;\u0026lt;C-l\u0026gt; map \u0026lt;C-k\u0026gt; \u0026lt;C-w\u0026gt;\u0026lt;C-k\u0026gt; \u0026quot;\u0026lt;F2\u0026gt;设置是否显示行号 nnoremap \u0026lt;silent\u0026gt; \u0026lt;F2\u0026gt; :set number!\u0026lt;CR\u0026gt; \u0026quot;空格打开关闭折叠 nnoremap \u0026lt;space\u0026gt; @=((foldclosed(line('.')) \u0026lt; 0) ? 'zc' : 'zo')\u0026lt;CR\u0026gt; 由于已经将 bash profile，vimrc 等存放在 github 私有仓库中，所以上述配置内容较少。\n有问题的同学，可以随时联系\n"}),a.add({id:13,href:'/wiki/part1/4-ways-to-learn/',title:"4 Ways to Learn",section:"Wikis",content:"四种学习方法 (来源：搜狐, 侵删) #   一、费曼学习法： #  费曼学习法的灵感源于诺贝尔物理奖获得者理查德费曼（Richard Feynman），运用费曼技巧,你只需花上20分钟就能深入理解知识点,而且记忆深刻,难以遗忘。知识有两种类型，我们绝大多数人关注的都是错误的那类。第一类知识注重了解某个事物的名称。第二类知识注重了解某件事物。这可不是一回事儿。著名的诺贝尔物理学家理查德·费曼（Richard Feynman）能够理解这二者间的差别，这也是他成功最重要的原因之一。事实上，他创造了一种学习方法，确保他会比别人对事物了解得更透彻。\n 运用步骤：\n1、获取知识（某概念） ，理解你所要学习的材料的内容。\n2、讲解/复述 你所获得的主要内容。\n3、用你自己的方式以 潜意识的形式 再次 复述 你所学到的知识。\n4、这一步是一个 可循环过程 ：不满意——纠错反馈；满意——尝试运用更简单精炼的语言概括。再用你所学到的知识解决实际问题，加以运用。\n5、反思 。 反思你在思考的时候在哪里卡了壳，着重这个地方，再次理解。这个过程至关重要！\n6、检验。 通过不断的进行实践检验才能巩固你对于该知识点的理解。\n二、思维导图学习法： #   思维导图法又称为心智图法（Mind mapping），是一项流行的全脑式学习方法，它能够将各种点子、想法以及它们之间的关联性以图像视觉的景象呈现。它能够将一些核心概念、事物与另一些概念、事物形象地概念组织起来，输入我们脑内的记忆树图。它允许我们对复杂的概念、信息、数据进行组织加工，以更形象、易懂的形式展现在我们面前。\n思维导图法总是从一些中心概念、问题入手。 非常典型的是一些与中心概念线形连接关键字、短语或图像。\n我们中的大多数人都是视觉导向的，通过运用结构、关键字、颜色、图像、超链接（以及声音），将外部概念引入我们的思维和生活。简而言之，心智图法就是将中心概念与关联概念连接起来的一种方法。 不同于我们在学校里所学到的直线性思考方法，心智图法通过训练运用全脑思考，来刺激我们的想象力和创造力。因此，它被认为是全面调动分析能力和创造能力的一种思考方法。\n 思维导图的要点：\n1、将主要概念、想法放置于图的中心位置。 最好用图片来表示它。\n2、尽量使用大空间，以便稍后你有足够的空间添加其他内容。\n3、如果有帮助的话，可以使用不同的颜色和大写字母。 个性化你的心智图。\n4、在心智图上寻找、发现关系。\n5、为次级主体建立次级中心。\n三、西蒙学习法 #   是指诺贝尔经济学奖获得者西蒙教授提出的一个理论：“对于一个有一定基础的人来说，只要真正肯下功夫，在6个月内就可以掌握任何一门学问。”\n西蒙教授立论所依据的实验心理的研究成果表明：一个人1分钟到1分半钟可以记忆一个信息，心理学把这样一个信息称为“块”，估记每一门学问所包含的信息量大约是5万块，如果1分钟能记忆1“块”，那么5万块大约需要1000个小时，以每星期学习40小时计算，要掌握一门学问大约需要用6个月。\n为了形象地说明，把西蒙学习法比做一把锥子。正如居里夫人所说，“知识的专一性像锥尖，精力的集中好比是锥子的作用力，时间的连续性好比是不停顿地使锥子往前钻进。” 西蒙学习法所支配的学习活动，呈现出一种尖锐猛烈、持续不断的态势。\n为了感谢西蒙的这个研究成果，教育心理学界称这种学习法为西蒙学习法，又名 “锥形学习法”。\n这种“锥形学习法”的高效原理在于，连续的长时间学习本身包涵对之前学习内容的应用，这样就省去了大量的复习时间。如果用烧水来做比喻，“锥形学习法”是连续的加热，所以热量散失的少；普通的间断学习是烧一会儿就停止加热，一段时间以后再继续加热，这样许多热量就白白散失了。两相比较，自然是持续“加热”效果显著了。\n原理：烧一壶开水，如果断断续续地烧，1万个小时也烧不开，如果连续烧，1个小时就够用了。\n四、SQ3R学习法 #  这种学习方法是由罗宾逊提出来的并盛行于美国大专院校。据了解，这种方法颇受中国大学生的喜爱，他们觉得这种方法人人都可以试用，都会取得一定的效果。\nSQ3R代表：\n纵览（Survey）\n提问（Question）\n阅读（Read）\n背诵（Recite）\n复习 (Revise）\n 1、纵览编辑\n纵览就是对全书进行快速的浏览，弄清这本书的基本内容，对作者的基本观点有一个初步印象.一般来说，先阅读作者的序言（前言）或后记，了解作者写这本书的意图和目的，继而仔细查阅其目录和索引，如有可能，略读各章的提要或小结，确定全书阅读，或取其某些章节精读。纵览往往可以了解到最新信息，启发自己的思路。\n2、提问编辑\n大学生在学习过程中，不仅要学会解决问题，而更重要的是学会提出问题。在读书时，要透过书中表面字句去捕捉问题，敢于在无疑处生疑，提出自己的设想。同时，要认真琢磨其中的某些观点，并把它和自己所掌握的有关观点相对比、相联系，进行评论，提出问题。有了问题，就会进一步去探索，从而可能提炼出新观点。\n3、阅读编辑\n阅读的目的是为了正确理解和深入掌握文章的精髓，对重点章节学深吃透，做到融会贯通，使其成为自己知识结构的牢固基础。读书的最佳境界是“读懂书上没有的东西”。就是要懂得从明看出暗，从静看出动，从是看出非。读书要能看出书本含蓄之处，也就是书本的言外意、弦外音，这要靠读者自己去思考、捕捉和体会。书的东西，是死的,静止化了，而科学知识却日新月异，要能从过去的书本中看到现在，从现在的书本中想到将来，这样就能\u0026quot;激活\u0026quot;死的知识。书本知识是一定时代人们认识水平的记录，因而带有时代的烙印。瑕瑜相杂、正误互见。看出或指出书本中的谬误、漏洞，并非专家、权威莫属，每一位深思的读者都能发现。因此，要养成思考的习惯，边读边想，必有所得。\n4、背诵编辑\n不是指逐句的复诵或默记，而是指在理解的基础上，集中精力把有关章节的中心思想和基本观点牢记在脑中，当然，不排除把某些重要的基本概念背诵出来。\n5、复习编辑\n需要长时间保留在记忆中的材料必须反复复习。注意每次复习，在内容上要有所开拓，有所发展。\nSQ3R学习法原则上适用于所有的学科领域。\n"}),a.add({id:14,href:'/wiki/part1/efficient-communication/',title:"Efficient Communication",section:"Wikis",content:"高效沟通 #  Efficient communication\n老板要善于提问 #  1. 引导 #  用提问的方式，\u0026quot;倒逼\u0026quot; 员工找到答案，从而提高员工的对与感与成就感。 永远不要给员工答案，要让员工给你答案，而且不要只给一个答案，一定要给多个答案。  2. 倾听 #  心态平和，毫无偏见，全面接收和理解对方的信息，而且不是只听自己想听的信息。  3. 共情 #   换位思考, 站在对方的立场设身处地思考和处理问题，晓之以理，动之以情。 (避免指责对方)  4. 高维 #  提升自己的格局观，能从全局利益、长远利益思考问题，解决问题。( 不纠结某一个细节)  5. 反馈 #  建立反馈机制，及时发现问题、解决问题、形成正向循环。 1-2-3 反馈机制（指定时间内处理不了问题，及时向上反馈）  好好说话的艺术 #  跟员工沟通 #  一对一会议 #  工作状态 个人发展 公司组织 员工对自己的看法 每半月一次 时间（30-60分钟）  绩效沟通 #  沟通一定要放在平时， 不要搞成像秋后算账一样！ 因为你是管理者， 不是地方监工 但要注意的是，反馈的过程中， 不是我在指责员工，而是我的帮助员工，一定要有帮扶的态度，这样员工会更容易接受。\n特立独行的员工 #  当在一个人身上花的精力和时间成本，大于你到外面找一个更好的人或者能力相当的人来替代他的时候，你就要坚决地把他替换掉。\n挽留离职员工 #  实在挽留不成的时候，也要注意经营好这份情意。  劝退员工 #  任何人都应该有可以纠正错误的机会，公司应该给员工这样的机会，员工也应该给公司同样的机会。  跟客户沟通 #  吸引客户的兴趣、帮客户发现问题和管理客户的期望。  跟老板沟通 #  了解你的的老板，赢得老板的信任，管理老板的期望，非暴力\u0026quot;怼\u0026quot; 老板。  "}),a.add({id:15,href:'/wiki/part1/m1-ability/',title:"M1 Ability",section:"Wikis",content:"快速提升一线管理者的战斗力 #  1. 认知升级 #  如何学习优秀管理者的底层思维模型？ 何为优秀的管理者？ 何为优秀的 Leader? 如何做到阴阳同体，Leader 的二维修炼？ 领导力如何快速修炼？\n目标：认知升级, 构建优秀管理者的思维模型\n2. 建团队 #  优秀员工的画像是什么样的？ 如何制作出优秀员工的画像？ 如何利用优秀员工画像选对人、培养人、淘汰人？ 如何提升团队的凝聚力？\n目标：掌握建团队的关键能力\n3. 定目标 #  如何正确理解团队目标？ 如何正确分解目标？ 如何统一团队目标和员工个人目标？ 如何运用PDCA达成团队目标？\n目标：掌握定目标的关键能力\n4. 追过程 #  追过程中常用的有效沟通如何做？ 如何和不同沟通风格的人沟通？ 目标达成不理想，如何有效沟通？ 追过程中常用的有效辅导如何做？ 不同类型员工的有效辅导方法？\n目标：掌握追过程的关键能力\n5. 拿结果 #  好过程和好结果的哪个更重要？ 如何通过Review帮助员工和团队获得成长？ 如何通过Review形成可持续拿结果的方法？\n目标：总结出可持续拿结果的方法\n"}),a.add({id:16,href:'/wiki/part1/README/',title:"Readme",section:"Wikis",content:"公共部分 #  公共部分内容\n"}),a.add({id:17,href:'/wiki/part2/cicd/',title:"Cicd",section:"Wikis",content:"Code Wiki #  Code Part #   dev\n"}),a.add({id:18,href:'/wiki/part2/gateway/',title:"Gateway",section:"Wikis",content:"Gateway #  智能网关趋势 #    HTTPS\n  Quic\n   GTC (Global Traffic Control 全局流量控制） #    工作原理 分布式监控 调度计算 下发执行\n  场景 网络出口故障 网络出口拥塞，被攻击 网络接入系统故障 区域性联通故障\n  GSLB (Global Server Load Balancing 全局服务器负载平衡) #    目的 降低对DNS 调度的依赖 加快止损速度\n  场景 内部服务故障 服务发布 内部服务压力不均 业务突增\n  "}),a.add({id:19,href:'/wiki/part2/kube/',title:"Kube",section:"Wikis",content:"Code Wiki #  Code Part #   dev\n"}),a.add({id:20,href:'/wiki/part2/linux/',title:"Linux",section:"Wikis",content:"Linux Wiki #  Basic #   Linux\n"}),a.add({id:21,href:'/wiki/part2/ops/',title:"Ops",section:"Wikis",content:"运维 #  接入 #  四层接入\n七层接入\nCDN\nIP 库\nNginx\n服务集群 #  发布\n容器\n调度\n容灾\n数据一致性\n容灾\n多活\n预案演练\nCI/CD #  持续集成\n持续部署\n数据库 #  同步\n数据恢复\n缓存 #  中间件 #  Kafka\n消息中间件 MQ\n数据安全及运维安全 #  WAF\n大数据及分布式计算 #  Hadoop\nCeph\nHive\n人工智能 #  语音识别 ASR\n人脸识别\n自然语言处理 NLP\n"}),a.add({id:22,href:'/wiki/part2/osinit/',title:"Osinit",section:"Wikis",content:"OS Init #  主机容器初始化 #  [osinit]https://init.airdb.host/\n osinit Repo\n软件包管理 #  Ubunut PPA (https://launchpad.net/~airdb)\nsudo apt-add-repository ppa:airdb/adb\n"}),a.add({id:23,href:'/wiki/part2/snapcraft/',title:"Snapcraft",section:"Wikis",content:"Ubuntu Snapcraft #  snapcraft push --release edge *.snap Pushing airdb_1.0_amd64.snap After pushing, an attempt will be made to release to 'edge' Preparing to push '/home/ubuntu/airdb/airdb_1.0_amd64.snap' to the store. Pushing airdb_1.0_amd64.snap [===================================================================================================================] 100% Processing...| Ready to release! Revision 1 of 'airdb' created. Track Arch Channel Version Revision latest amd64 stable - - candidate - - beta - - edge 1.0 1 The 'edge' channel is now open. snap/snapcraft.yaml name: airdb version: '1.0' summary: An interactive web server. description: | HTTPLab let you inspect HTTP requests and forge responses. confinement: devmode #base: core18 parts: airdb-adb: plugin: nil source: http://ftp.gnu.org/gnu/hello/hello-2.10.tar.gz plugin: autotools apps: airdb: command: bin/hello Commands #  snapcraft register xxx-project snapcraft clean airdb-adb -s pull snapcraft push stable stable *.snap snapcraft push --release edge *.snap "}),a.add({id:24,href:'/wiki/part2/sre/',title:"Sre",section:"Wikis",content:"SRE 介绍 #  Site Reliability Engineering\n一、SRE起源和发展 #  IT领域一直有很多趋势和流行关键词，比如微服务和DevOps，现在国内又兴起了SRE，它在传统运维之外又纳入更多的开发和流程部分。SRE是Site Reliability Engineer的简称，由谷歌公司首先提出，一开始是公司内部定义的一个工种。谷歌的SRE工程师对Borg分布式集群管理系统以及在此之上运行的Gmail、Google Docs、Web Search等以及各种APP应用进行运维。\n这个岗位的工程师具有开发能力，又了解一些系统管理的知识，他们把一些最佳实践、方式、流程、方法都固化成代码，用这种方式去应对规模性的扩张，去应对复杂度的上升。从名字其实就可以看出SRE不只是做Operation方面的工作，更多是保障整个服务的稳定性。\nSRE不仅仅是对分布式系统运维工程师的职业要求，还涉及运维的自动化、开发运维一体化、持续集成持续开发等理念、监控系统、部署、容量规划、可靠性技术和实践和运维团队建设等方面的内容。可为云服务提供商提高分布式系统的资源利用率，降低运营和运维成本，让系统可靠和稳定地运行，提升用户体验。\n随着互联网的快速发展，分布式系统规模急剧扩展，新型系统的运维要求对传统运维理念提出了新的挑战。随着谷歌对大规模分布式集群和互联网应用运维经验的积累，SRE的实践理念得到国外各大互联网公司的采纳和应用。Site Reliability Engineer逐渐朝着Site Reliability Engineering的理论化方向发展。\n由于互联网行业的特性和对速度的追求，一般这些新理念和新技术的发端和普及都是从互联网企业开始，国内也不例外。虽然很多国内互联网企业并没有明确提及SRE这个岗位名称，但是据我所知他们也是在向着SRE理念提及的很多方向在前进，比如自动化、工具化、平台化等等。不管国内称之为PE、运维工程师还是其他什么，其实做的事情也就是SRE在倡导的DevOps的运维实践\n二、定位、方向与职责 #  总结一下，SRE\n从岗位的角度上看：运维工程师升级版 从运维的方式上看：自动化、智能化、工具化、平台化 从工作的结果上看：保证系统稳定的前提下提高系统效率，平衡系统稳定性和用户体验的关系\n三、实践 #  从SRE成功实践的几大要素看：\n 1、具有研发能力 2、一定要设定服务的SLA 3、有余量的预估 4、 SRE与研发有共享的资源工具 5、 SRE承担不超过50%的运维工作量 6、 每个事故都要做事后分析，并要聚焦于流程和技术。  "}),a.add({id:25,href:'/wiki/part3/README/',title:"Readme",section:"Wikis",content:"Application 性能优化 #  Linux 底层优化 #  CPU￼ #  进程和 CPU 原理\n 进程、线程与协程 CPU 调度 中断系统 CPU 缓存 NUMA  性能指标\n 平均复杂 CPU 使用率：用户 CPU, 系统CPU，iowait, 软中断，硬中断，窃取 CPU，客户 CPU. 上下文切换：自愿切换，非自愿切换 CPU 缓存命中率  性能剖析\n top/htop/ps vmstat mpstat pidstat strace perf execsnoop proc 文件系统  调优方法\n CPU 绑定 affinity 进程 CPU 资源限制 进程优先级调整 中断负载均衡 CPU 缓存 NUMA 优化  内存 #  内存原理\n 地址空间 虚拟内存 内存分配与回收 缓存与缓冲区 swap  性能指标\n 系统内存使用 进程内存使用 缓存与缓冲区命中率  性能剖析\n free top sar vmstat cachestat cachetop memleak proc 文件系统  调优方法\n 利用缓存与缓冲区 减少 SWAP 使用 减少动态内存分配 优化 NUMA 限制进程内存资源 HugePage  网络 #  网络原理\n 网络配置 TCP/IP 协议 网络收据收发 高级路由 网络 QOS 网络防火墙  性能指标\n 吞吐量：BPS, QPS, PPS 延迟 丢包 TCP 重传  性能剖析\n ethtool sar ping netstat/ss ifstat ifconfig tcpdump iptables traceroute ipcontrack perf  调优方法\n 网卡调优：MTU， 队列长度，链路聚合 协议调优：HTTP, TCP, overlay 资源控制：QoS 内核调优：NAT 优化，功能卸载，负载均衡，DPDK  磁盘IO￼ #  磁盘原理\n 磁盘管理 磁盘内型，RAID 选型 磁盘接口 磁盘 I/O 栈  性能指标\n 使用率 IOPS 吞吐量 IO Wait  性能剖析\n dstat sar iostat pidstat iotop iolatency blktrace fio perf  调优方法\n 系统调用 I/O 资源控制, 写对齐 充分利用缓存 RAID I/O 隔离  文件系统 #  文件原理：\n 虚拟文件系统 文件系统 IO 栈 文件系统缓 文件系统种类  性能指标：\n 容量 IOPS 缓存命中率  性能剖析\n df strace vmstat sar perf proc 文件系统  调优方法\n 文件系统内型 利用文件系统缓存 I/O 隔离  Linux 内核优化 #  内核原理\n 内核态 模型  性能指标\n性能剖析\n BPF perf proc 文件系统  调优方法\n 内核参数  应用层优化 #  应用程序 #  性能指标\n 吞吐量 响应时间 资源使用率  性能剖析\n USE 方法：使用率，饱和度，初五 进程剖析：进程状态，资源使用率，I/O 剖析， 系统调用，热点函数，动态追踪 APM  调优方法\n 逻辑优化 编程语言 算法调优 非阻塞 I/O 利用缓存与缓冲区 异步处理与并发 垃圾回收  架构设计 #  空间换时间\n 缓存 缓冲区 冗余数据  时间换空间：\n 压缩编码 页面交换  并行处理\n 多线程 多进程 协程 分布式  异步处理\n 异步 I/O 消息队列 事件通知  ￼\n性能监控 #  时间序列分析\n 历史趋势分析 性能模型构建 未来趋势预测  服务调用追踪\n 服务调用流程跟踪 服务调用性能分析 服务调用链拓扑展示  数据可视化\n 趋势图 散点图 热图 饼图  告警通知\n 阈值选择 动态阈值 报警策略 通知渠道  性能测试 #  明确需求\n 系统资源需求 应用程序需求  环境假设\n 合理的假设 生产环境模拟 生产负载模拟  性能测试\n 基准测试 负载测试 压力测试  结果分析\n 应用程序瓶颈 数据库瓶颈 系统资源瓶颈  "}),a.add({id:26,href:'/wiki/part4/defensive-programming/',title:"Defensive Programming",section:"Wikis",content:"Defensive Programming #  Rules on how to employ Defensive Programming in your codebase: #    Protect your code from invalid data coming from outside, wherever you decide outside is. External systems, files, or any call from outside of the module/component. Establish “trust boundaries” — everything outside of the boundary is dangerous, everything inside of the boundary is safe. In the barricade code, validate all input data.\n  After you have checked for bad data, decide how to handle it. Defensive Programming is NOT about swallowing errors or hiding bugs. Choose a strategy to deal with bad data: return an error and stop right away (fast fail), return a neutral value, substitute data values… Make sure that the strategy is clear and consistent.\n  Don’t assume that a function call or method call outside of your code will work as advertised. Make sure that you understand and test error handling around external APIs and libraries.\n  Use assertions to document assumptions and to highlight “impossible” conditions. This is especially important in large systems that have been maintained by different people over time, or in high-reliability code.\n  Add diagnostic code, logging and tracing intelligently to help explain what’s going on at run-time, especially if you run into a problem.\n  Standardize error handling. Decide how to handle “normal errors” or “expected errors” and warnings, and do all of this consistently.\n  "}),a.add({id:27,href:'/wiki/part4/exec_base64/',title:"Exec Base64",section:"Wikis",content:"Base64 入侵\n PyPI 官方仓库遭遇request恶意包投毒\n[dean.airdb.local test]$ echo -e \u0026ldquo;import os; os.system(\u0026quot;ls\u0026quot;)\u0026rdquo; | base64 aW1wb3J0IG9zOyBvcy5zeXN0ZW0oImxzIikK\n[dean.airdb.local test]$ python -c \u0026ldquo;import base64; exec(base64.b64decode(\u0026lsquo;aW1wb3J0IG9zOyBvcy5zeXN0ZW0oImxzIikK\u0026rsquo;))\u0026rdquo; test test.log\n[dean.airdb.local test]$ echo -e aW1wb3J0IG9zOyBvcy5zeXN0ZW0oImxzIikK | base64 -d import os; os.system(\u0026ldquo;ls\u0026rdquo;)\n"}),a.add({id:28,href:'/wiki/README/',title:"Readme",section:"Wikis",content:"Code Wiki #  Code Part #   dev\n"})})()